@page "/admin/users"
@rendermode InteractiveServer
@attribute [Authorize(Roles = "Admin")]

@using Microsoft.AspNetCore.Identity
@using sv_cd3ac2f779cf4323bb40962f2d3115b8.Data

@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Manage all users and their roles.</p>

@if (userRows is null)
{
    <p><em>Loading users...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var row in userRows)
            {
                <tr>
                    <td>@row.Email</td>
                    <td>@row.Roles</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<UserRow>? userRows;

    protected override async Task OnInitializedAsync()
    {
        var users = UserManager.Users.ToList();
        userRows = [];

        foreach (var user in users)
        {
            var roles = await UserManager.GetRolesAsync(user);
            userRows.Add(new UserRow(user.Email!, string.Join(", ", roles)));
        }
    }

    private record UserRow(string Email, string Roles);
}

